-- Disable FK checks during migration
SET session_replication_role = replica;

CREATE TABLE IF NOT EXISTS "ir_user_access_apps" ("id"  BIGSERIAL , "mark_user_id" BIGINT NOT NULL, "access_token" TEXT NOT NULL, "user_agent" VARCHAR(255) NOT NULL, "user_ip" VARCHAR(100) NOT NULL, "created_at" BIGINT, "updated_at" BIGINT, PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "ir_display_types" ("id"  BIGSERIAL , "title" VARCHAR(100) NOT NULL, "status" SMALLINT DEFAULT 1, "created_at" BIGINT, "updated_at" BIGINT, PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "ir_regions" ("id"  BIGSERIAL , "title" VARCHAR(100) NOT NULL, "created_at" BIGINT, "updated_at" BIGINT, PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "ir_event_organizers" ("id"  BIGSERIAL , "name" VARCHAR(100) NOT NULL, "image" VARCHAR(255), "detail" TEXT NOT NULL, "created_at" BIGINT, "updated_at" BIGINT, PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "ir_type_content_details" ("id"  BIGSERIAL , "name" VARCHAR(100) NOT NULL, "created_at" BIGINT, "updated_at" BIGINT, PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "ir_tags" ("id"  BIGSERIAL , "title" VARCHAR(100) NOT NULL, "created_at" BIGINT, "updated_at" BIGINT, PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "ir_actress" ("id"  BIGSERIAL , "name" VARCHAR(100) NOT NULL, "image" VARCHAR(255) NOT NULL, "gender" SMALLINT, "birth_of_day" TIMESTAMP WITH TIME ZONE, "detail" TEXT, "created_at" BIGINT, "updated_at" BIGINT, PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "ir_abouts" ("id"  BIGSERIAL , "description" TEXT, "type" SMALLINT DEFAULT 1, "created_at" BIGINT, "updated_at" BIGINT, PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "ir_reports" ("id"  BIGSERIAL , "title" VARCHAR(100) NOT NULL, "description" TEXT, "type" SMALLINT DEFAULT 1, "status" SMALLINT DEFAULT 1, "created_at" BIGINT, "updated_at" BIGINT, PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "ir_users" ("id"  BIGSERIAL , "display_name" VARCHAR(100) NOT NULL, "display_name_anonymous" VARCHAR(100), "photo" VARCHAR(100), "description" TEXT, "email" VARCHAR(100) NOT NULL UNIQUE, "phone" VARCHAR(100) UNIQUE, "username" VARCHAR(100) NOT NULL UNIQUE, "username_anonymous" VARCHAR(100) NOT NULL UNIQUE, "password" VARCHAR(100) NOT NULL, "gender" SMALLINT, "is_verified" SMALLINT DEFAULT 0, "date_of_birth" BIGINT, "referal_code" VARCHAR(5), "coins" INTEGER DEFAULT 0, "status" SMALLINT DEFAULT 1, "is_anonymous" SMALLINT DEFAULT 0, "expired_verified" BIGINT, "created_at" BIGINT, "updated_at" BIGINT, "deleted_at" BIGINT, PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "ir_base_name_anonymous_users" ("id"  BIGSERIAL , "name" VARCHAR(100) NOT NULL, "type" SMALLINT DEFAULT 1, "created_at" BIGINT, "updated_at" BIGINT, PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "ir_base_name_anonymous_user_usages" ("id"  BIGSERIAL , "name" VARCHAR(100) NOT NULL, "total" INTEGER, "created_at" BIGINT, "updated_at" BIGINT, PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "ir_topic_posts" ("id"  BIGSERIAL , "text_title" VARCHAR(100) NOT NULL UNIQUE, "created_at" BIGINT, "updated_at" BIGINT, PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "ir_subregions" ("id"  BIGSERIAL , "title" VARCHAR(100) NOT NULL, "regions_id" BIGINT NOT NULL REFERENCES "ir_regions" ("id"), "created_at" BIGINT, "updated_at" BIGINT, PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "ir_contents" ("id"  BIGSERIAL , "title" VARCHAR(100) NOT NULL, "slug" VARCHAR(100) NOT NULL UNIQUE, "status" SMALLINT DEFAULT 0, "display_types_id" BIGINT NOT NULL REFERENCES "ir_display_types" ("id"), "created_at" BIGINT, "updated_at" BIGINT, PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "ir_following_users" ("id"  BIGSERIAL , "following_id" BIGINT NOT NULL REFERENCES "ir_users" ("id"), "users_id" BIGINT NOT NULL REFERENCES "ir_users" ("id"), "created_at" BIGINT, "updated_at" BIGINT, PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "ir_reported_users" ("id"  BIGSERIAL , "description" TEXT, "reports_id" BIGINT NOT NULL REFERENCES "ir_reports" ("id"), "users_id" BIGINT NOT NULL REFERENCES "ir_users" ("id"), "source_id" BIGINT NOT NULL, "type" SMALLINT DEFAULT 1, "created_at" BIGINT, "updated_at" BIGINT, PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "ir_notifications" ("id"  BIGSERIAL , "users_id" BIGINT NOT NULL REFERENCES "ir_users" ("id"), "source_id" BIGINT NOT NULL, "type" SMALLINT DEFAULT 0, "is_read" SMALLINT DEFAULT 0, "message" TEXT, "send_mail_at" BIGINT, "created_at" BIGINT, "updated_at" BIGINT, PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "ir_countries" ("id"  BIGSERIAL , "title" VARCHAR(100) NOT NULL, "subregions_id" BIGINT NOT NULL REFERENCES "ir_subregions" ("id"), "created_at" BIGINT, "updated_at" BIGINT, PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "ir_provinces" ("id"  BIGSERIAL , "title" VARCHAR(100) NOT NULL, "countries_id" BIGINT NOT NULL REFERENCES "ir_countries" ("id"), "created_at" BIGINT, "updated_at" BIGINT, PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "ir_citys" ("id"  BIGSERIAL , "title" VARCHAR(100) NOT NULL, "provinces_id" BIGINT NOT NULL REFERENCES "ir_provinces" ("id"), "created_at" BIGINT, "updated_at" BIGINT, PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "ir_vanues" ("id"  BIGSERIAL , "title" VARCHAR(100) NOT NULL, "citys_id" BIGINT NOT NULL REFERENCES "ir_citys" ("id"), "provinces_id" BIGINT NOT NULL REFERENCES "ir_provinces" ("id"), "countries_id" BIGINT NOT NULL REFERENCES "ir_countries" ("id"), "created_at" BIGINT, "updated_at" BIGINT, PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "ir_content_details" ("id"  BIGSERIAL , "title" VARCHAR(100) NOT NULL, "slug" VARCHAR(100) NOT NULL UNIQUE, "schedule_start" BIGINT, "schedule_end" BIGINT, "date_start" BIGINT, "date_end" BIGINT, "description" TEXT, "image" VARCHAR(200), "vanues_id" BIGINT NOT NULL REFERENCES "ir_vanues" ("id"), "contents_id" BIGINT NOT NULL REFERENCES "ir_contents" ("id"), "event_organizers_id" BIGINT NOT NULL REFERENCES "ir_event_organizers" ("id"), "is_trending" SMALLINT DEFAULT 0, "status" SMALLINT DEFAULT 2, "type_content_details_id" BIGINT NOT NULL REFERENCES "ir_type_content_details" ("id"), "impression" BIGINT NOT NULL DEFAULT 0, "created_at" BIGINT, "updated_at" BIGINT, PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "ir_groups" ("id"  BIGSERIAL , "title" VARCHAR(100) NOT NULL, "slug" VARCHAR(100) NOT NULL UNIQUE, "users_id" BIGINT NOT NULL REFERENCES "ir_users" ("id"), "description" TEXT, "citys_id" BIGINT NOT NULL REFERENCES "ir_citys" ("id"), "content_details_id" BIGINT NOT NULL REFERENCES "ir_content_details" ("id"), "max_members" INTEGER, "is_gender" SMALLINT DEFAULT 0, "is_anonymous" SMALLINT DEFAULT 0, "is_private" SMALLINT DEFAULT 0, "status" SMALLINT DEFAULT 1, "password_join" VARCHAR(6), "created_at" BIGINT, "updated_at" BIGINT, PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "ir_content_detail_tags" ("id"  BIGSERIAL , "tags_id" BIGINT NOT NULL REFERENCES "ir_tags" ("id"), "content_details_id" BIGINT NOT NULL REFERENCES "ir_content_details" ("id"), "created_at" BIGINT, "updated_at" BIGINT, PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "ir_content_detail_actress" ("id"  BIGSERIAL , "actress_id" BIGINT NOT NULL REFERENCES "ir_actress" ("id"), "content_details_id" BIGINT NOT NULL REFERENCES "ir_content_details" ("id"), "created_at" BIGINT, "updated_at" BIGINT, PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "ir_content_detail_followers" ("id"  BIGSERIAL , "content_details_id" BIGINT NOT NULL REFERENCES "ir_content_details" ("id"), "users_id" BIGINT NOT NULL REFERENCES "ir_users" ("id"), "created_at" BIGINT, "updated_at" BIGINT, PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "ir_group_members" ("id"  BIGSERIAL , "groups_id" BIGINT NOT NULL REFERENCES "ir_groups" ("id"), "users_id" BIGINT NOT NULL REFERENCES "ir_users" ("id"), "status" SMALLINT DEFAULT 1, "created_at" BIGINT, "updated_at" BIGINT, PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "ir_chat_groups" ("id"  BIGSERIAL , "messages" TEXT, "groups_id" BIGINT NOT NULL REFERENCES "ir_groups" ("id"), "file" VARCHAR(100), "users_id" BIGINT NOT NULL REFERENCES "ir_users" ("id"), "created_at" BIGINT, "updated_at" BIGINT, PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "ir_groups_posts" ("id"  BIGSERIAL , "caption_post" TEXT, "photo" VARCHAR(100), "content_details_id" BIGINT NOT NULL REFERENCES "ir_content_details" ("id"), "groups_id" BIGINT NOT NULL REFERENCES "ir_groups" ("id"), "users_id" BIGINT NOT NULL REFERENCES "ir_users" ("id"), "created_at" BIGINT, "updated_at" BIGINT, PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "ir_post_content_details" ("id"  BIGSERIAL , "caption_post" TEXT, "caption_post_raw" TEXT, "slug" VARCHAR(100) NOT NULL UNIQUE, "users_id" BIGINT NOT NULL REFERENCES "ir_users" ("id"), "type" SMALLINT NOT NULL DEFAULT 0, "is_accepted" SMALLINT NOT NULL DEFAULT 0, "post_category" SMALLINT NOT NULL DEFAULT 0, "is_official" SMALLINT NOT NULL DEFAULT 0, "groups_id" BIGINT REFERENCES "ir_groups" ("id"), "created_at" BIGINT, "updated_at" BIGINT, PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "ir_chat_groups_status" ("id"  BIGSERIAL , "groups_id" BIGINT NOT NULL REFERENCES "ir_groups" ("id"), "users_id" BIGINT NOT NULL REFERENCES "ir_users" ("id"), "chat_groups_id" BIGINT NOT NULL REFERENCES "ir_chat_groups" ("id"), "status" SMALLINT DEFAULT 1, "created_at" BIGINT, "updated_at" BIGINT, PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "ir_groups_posts_comments" ("id"  BIGSERIAL , "comment_posts" TEXT, "group_posts_id" BIGINT NOT NULL REFERENCES "ir_groups_posts" ("id"), "users_id" BIGINT NOT NULL REFERENCES "ir_users" ("id"), "created_at" BIGINT, "updated_at" BIGINT, PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "ir_groups_posts_likes" ("id"  BIGSERIAL , "group_posts_id" BIGINT NOT NULL REFERENCES "ir_groups_posts" ("id"), "users_id" BIGINT NOT NULL REFERENCES "ir_users" ("id"), "created_at" BIGINT, "updated_at" BIGINT, PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "ir_file_post_content_details" ("id"  BIGSERIAL , "post_content_details_id" BIGINT NOT NULL REFERENCES "ir_post_content_details" ("id"), "file" VARCHAR(100), "created_at" BIGINT, "updated_at" BIGINT, PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "ir_comment_post_content_details" ("id"  BIGSERIAL , "comment_post" TEXT, "parent_id" BIGINT REFERENCES "ir_comment_post_content_details" ("id"), "post_content_details_id" BIGINT NOT NULL REFERENCES "ir_post_content_details" ("id"), "users_id" BIGINT NOT NULL REFERENCES "ir_users" ("id"), "created_at" BIGINT, "updated_at" BIGINT, PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "ir_like_post_content_details" ("id"  BIGSERIAL , "post_content_details_id" BIGINT NOT NULL REFERENCES "ir_post_content_details" ("id"), "users_id" BIGINT NOT NULL REFERENCES "ir_users" ("id"), "created_at" BIGINT, "updated_at" BIGINT, PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "ir_impression_post_content_details" ("id"  BIGSERIAL , "post_content_details_id" BIGINT NOT NULL REFERENCES "ir_post_content_details" ("id"), "users_id" BIGINT NOT NULL REFERENCES "ir_users" ("id"), "created_at" BIGINT, "updated_at" BIGINT, PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "ir_segmented_post_content_details" ("id"  BIGSERIAL , "post_content_details_id" BIGINT NOT NULL REFERENCES "ir_post_content_details" ("id"), "users_id" BIGINT NOT NULL REFERENCES "ir_users" ("id"), "content_details_id" BIGINT NOT NULL REFERENCES "ir_content_details" ("id"), "created_at" BIGINT, "updated_at" BIGINT, PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "ir_like_comment_post_content_details" ("id"  BIGSERIAL , "comment_post_content_details_id" BIGINT NOT NULL REFERENCES "ir_comment_post_content_details" ("id"), "users_id" BIGINT NOT NULL REFERENCES "ir_users" ("id"), "created_at" BIGINT, "updated_at" BIGINT, PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "ir_topic_post_relations" ("id"  BIGSERIAL , "post_content_details_id" BIGINT NOT NULL REFERENCES "ir_post_content_details" ("id") ON DELETE CASCADE, "users_id" BIGINT NOT NULL REFERENCES "ir_users" ("id") ON DELETE CASCADE, "topic_posts_id" BIGINT NOT NULL REFERENCES "ir_topic_posts" ("id") ON DELETE CASCADE, "created_at" BIGINT, "updated_at" BIGINT, PRIMARY KEY ("id"));

SET session_replication_role = DEFAULT;
